mapper.select:
SELECT id, supplier_code, name, contact_name, phone, status, creator, remark, created_at, updated_at, deleted FROM clinic_supplier WHERE deleted = 0
AND (supplier_code LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%') OR contact_name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_supplier
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
